const { Resend } = require("resend");

const resend = new Resend(process.env.RESEND_API_KEY);

const FROM = process.env.RESEND_FROM_EMAIL || "onboarding@resend.dev";
const OWNER = process.env.RESEND_OWNER_EMAIL;
const PAGE_URL = process.env.LANDING_PAGE_URL || "";

// REPLACE bбє±ng offer-specific content khi wire
const OFFER = {
  product_name: "{{PRODUCT_NAME}}",
  brand_name: "{{BRAND_NAME}}",
  sender_name: "{{SENDER_NAME}}",
  zalo_number: "{{ZALO_NUMBER}}",
};

function validate(data) {
  const name = (data.name || "").trim();
  const phone = (data.phone || "").trim();
  const email = (data.email || "").trim().toLowerCase();
  if (!name) return { ok: false, error: "Thiбєїu hб»Ќ tГЄn" };
  if (!phone) return { ok: false, error: "Thiбєїu sб»‘ Д‘iб»‡n thoбєЎi" };
  if (!/^[0-9+\s().-]{9,15}$/.test(phone)) return { ok: false, error: "SДђT khГґng hб»Јp lб»‡" };
  if (!email) return { ok: false, error: "Thiбєїu email" };
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) return { ok: false, error: "Email khГґng hб»Јp lб»‡" };
  return {
    ok: true,
    data: {
      name,
      phone,
      email,
      utm_source: data.utm_source,
      utm_campaign: data.utm_campaign,
      message: data.message,
    },
  };
}

function formatPhoneVN(phone) {
  const d = phone.replace(/\D/g, "");
  if (d.length === 10) return `${d.slice(0, 4)} ${d.slice(4, 7)} ${d.slice(7)}`;
  return phone;
}

function timestampVN() {
  return new Intl.DateTimeFormat("vi-VN", {
    timeZone: "Asia/Ho_Chi_Minh",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).format(new Date());
}

function renderLeadEmailHTML(lead) {
  return `<!DOCTYPE html><html lang="vi"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1"/></head>
<body style="margin:0;padding:0;background:#f5f5f7;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#1a1a1a;">
<table role="presentation" cellpadding="0" cellspacing="0" width="100%" style="background:#f5f5f7;"><tr><td align="center" style="padding:32px 16px;">
<table role="presentation" cellpadding="0" cellspacing="0" width="100%" style="max-width:560px;background:#fff;border-radius:12px;">
<tr><td style="padding:32px 24px;">
<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">ChГ o anh/chб»‹ ${lead.name},</p>
<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">Em lГ  ${OFFER.sender_name} tб»« ${OFFER.brand_name}. Em vб»«a nhбє­n thГґng tin Д‘Дѓng kГЅ cб»§a anh/chб»‹ vб»Ѓ <strong>${OFFER.product_name}</strong>.</p>
<!-- SKILL: thay block dЖ°б»›i Д‘Гўy bбє±ng email pattern P1/P2/P3/P4 Д‘ГЈ Д‘Ж°б»Јc user duyб»‡t -->
<p style="margin:0 0 24px;font-size:16px;line-height:1.5;">Em sбєЅ liГЄn hб»‡ qua sб»‘ ${formatPhoneVN(lead.phone)} trong vГІng 24h tб»›i Д‘б»ѓ hб»— trб»Ј anh/chб»‹.</p>
<p style="margin:24px 0 0;font-size:14px;color:#666;">CГі gГ¬ cбє§n gбєҐp, nhбєЇn em Zalo: <strong>${OFFER.zalo_number}</strong>.</p>
<p style="margin:24px 0 0;font-size:14px;color:#666;">вЂ” ${OFFER.sender_name}<br/>${OFFER.brand_name}</p>
</td></tr></table>
<p style="margin:16px 0 0;font-size:12px;color:#999;text-align:center;">Anh/chб»‹ nhбє­n email nГ y vГ¬ Д‘ГЈ Д‘Дѓng kГЅ tбєЎi ${PAGE_URL}.</p>
</td></tr></table></body></html>`;
}

function renderOwnerEmailHTML(lead) {
  return `<pre style="font-family:monospace;font-size:14px;">
Lead mб»›i tб»« ${PAGE_URL}

TГЄn:       ${lead.name}
SДђT:       ${formatPhoneVN(lead.phone)}
Email:     ${lead.email}
Source:    ${lead.utm_source || "direct"}
Campaign:  ${lead.utm_campaign || "-"}
Thб»ќi gian: ${timestampVN()}
${lead.message ? `Ghi chГє:   ${lead.message}` : ""}

Quick actions:
- Gб»Ќi:   tel:${lead.phone.replace(/\D/g, "")}
- Zalo:  https://zalo.me/${lead.phone.replace(/\D/g, "")}
- Email: mailto:${lead.email}
</pre>`;
}

module.exports = async (req, res) => {
  if (req.method !== "POST") {
    return res.status(405).json({ ok: false, error: "Method not allowed" });
  }

  try {
    const body = typeof req.body === "string" ? JSON.parse(req.body) : req.body;
    const result = validate(body || {});
    if (!result.ok) return res.status(400).json({ ok: false, error: result.error });
    const lead = result.data;

    const [leadEmail, ownerEmail] = await Promise.all([
      resend.emails.send({
        from: FROM,
        to: lead.email,
        subject: `${lead.name}, Д‘ГЈ ghi nhбє­n Д‘Дѓng kГЅ ${OFFER.product_name}`,
        html: renderLeadEmailHTML(lead),
        replyTo: OWNER,
      }),
      resend.emails.send({
        from: FROM,
        to: OWNER,
        subject: `рџ”Ґ Lead mб»›i вЂ” ${lead.name} (${formatPhoneVN(lead.phone)}) вЂ” ${OFFER.product_name}`,
        html: renderOwnerEmailHTML(lead),
        replyTo: lead.email,
      }),
    ]);

    if (leadEmail.error || ownerEmail.error) {
      console.error("Resend error:", leadEmail.error, ownerEmail.error);
      return res.status(500).json({ ok: false, error: "Email service tбєЎm lб»—i, thб»­ lбєЎi sau" });
    }

    return res.status(200).json({ ok: true });
  } catch (err) {
    console.error("/api/submit fatal:", err);
    return res.status(500).json({ ok: false, error: "Lб»—i server" });
  }
};
